import type { Update } from "../models/Update";
export type Filter = ((update: Update) => boolean) & {
    and: (other: Filter) => Filter;
    or: (other: Filter) => Filter;
    not: () => Filter;
};
export declare const filters: {
    TEXT: Filter;
    COMMAND: Filter;
    PHOTO: Filter;
    STICKER: Filter;
    ALL: Filter;
};
